prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName ?choreo ?modelName WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "6c9090aeef814120944b4885c7343b63" .
  OPTIONAL { ?model bbo:name ?modelName . }
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .
  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName .
  FILTER(CONTAINS(LCASE(STR(?taskName)), LCASE("Complaint rejected")))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?name ?label ?type WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "6c9090aeef814120944b4885c7343b63" .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .
  ?task tai:belongsTo ?choreo .

  OPTIONAL { ?task bbo:name ?name . }
  OPTIONAL { ?task rdfs:label ?label . }
  OPTIONAL { ?task a ?type . }

  FILTER(
    CONTAINS(LCASE(STR(COALESCE(?name,""))), LCASE("complaint")) ||
    CONTAINS(LCASE(STR(COALESCE(?label,""))), LCASE("complaint")) ||
    CONTAINS(LCASE(STR(?task)), LCASE("complaint"))
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelIdProp ?modelIdVal ?task ?taskName WHERE {
  {
    ?model a bboExt:Model ;
           tai:normalizedId "6c9090aeef814120944b4885c7343b63" ;
           tai:originalId ?orig .
    BIND("normalizedId" AS ?modelIdProp)
    BIND("6c9090aeef814120944b4885c7343b63" AS ?modelIdVal)
  }
  UNION
  {
    ?model a bboExt:Model ;
           tai:originalId "6c9090aeef814120944b4885c7343b63" ;
           tai:normalizedId ?norm .
    BIND("originalId" AS ?modelIdProp)
    BIND("6c9090aeef814120944b4885c7343b63" AS ?modelIdVal)
  }

  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .
  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .
  OPTIONAL { ?task bbo:name ?taskName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?start ?startName ?task ?taskName WHERE {
  ?model a bboExt:Model ;
         tai:originalId "6c9090aeef814120944b4885c7343b63" ;
         tai:normalizedId "6c9090aeef814120944b4885c7343b63" .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name "Complaint rejected" .

  ?start a bboExt:StartEvent ;
         tai:belongsTo ?choreo .
  OPTIONAL { ?start bbo:name ?startName . }

  FILTER NOT EXISTS {
    ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)* ?other .
    # any reachable node is allowed; we only care whether the task itself is reachable
    FILTER(false)
  }

  FILTER NOT EXISTS {
    ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
  }

  BIND("UNREACHABLE_FROM_THIS_START" AS ?marker)
  OPTIONAL { ?task bbo:name ?taskName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?start ?startName (COUNT(DISTINCT ?reachableTask) AS ?reachCount) WHERE {
  ?model a bboExt:Model ;
         tai:originalId "6c9090aeef814120944b4885c7343b63" ;
         tai:normalizedId "6c9090aeef814120944b4885c7343b63" .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name "Complaint rejected" .

  ?start a bboExt:StartEvent ;
         tai:belongsTo ?choreo .
  OPTIONAL { ?start bbo:name ?startName . }

  OPTIONAL {
    ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?reachableTask .
    FILTER(?reachableTask = ?task)
  }
}
GROUP BY ?choreo ?start ?startName
ORDER BY ?choreo ?start
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
